import React, { useState, useEffect } from 'react';
import { motion, useScroll, useTransform, AnimatePresence } from 'framer-motion';
import {
  ArrowRightIcon,
  CheckBadgeIcon,
  ChartBarIcon,
  ChatBubbleLeftRightIcon,
  ShieldCheckIcon,
  UserGroupIcon,
  DocumentTextIcon,
  GlobeAltIcon,
  ClockIcon,
  StarIcon,
  ChevronRightIcon,
  PlayIcon,
  SparklesIcon,
  FingerPrintIcon,
  MapPinIcon,
} from '@heroicons/react/24/outline';
import { Link } from 'react-router-dom';
import CountUp from 'react-countup';
import { useInView } from 'react-intersection-observer';

/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
   IMAGE REGISTRY вЂ” all contextually relevant Sri Lanka photos
   Each entry has a primary Unsplash URL + picsum fallback
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */
const IMGS = {
  /* в”Ђв”Ђ Hero slideshow: iconic civic/political landmarks в”Ђв”Ђ */
  hero: [
    {
      name: 'Sri Lanka Parliament, Sri Jayawardenepura Kotte',
      region: 'Western Province',
      // Sri Lanka Parliament building exterior
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/1280px-Sri_Lanka_Parliament_2.jpg',
      fb: 'https://picsum.photos/seed/parliament/1600/900',
    },
    {
      name: "President's House, Colombo Fort",
      region: 'Colombo',
      // President's secretariat / Queens House
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/1280px-Presidential_Secretariat%2C_Colombo.jpg',
      fb: 'https://picsum.photos/seed/presidentshouse/1600/900',
    },
    {
      name: 'Supreme Court of Sri Lanka',
      region: 'Colombo 12',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Supreme_Court_of_Sri_Lanka.jpg/1280px-Supreme_Court_of_Sri_Lanka.jpg',
      fb: 'https://picsum.photos/seed/supremecourt/1600/900',
    },
    {
      name: 'Galle Face Green, Colombo',
      region: 'Colombo 03',
      src: 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=1600&q=85',
      fb: 'https://picsum.photos/seed/galleface/1600/900',
    },
    {
      name: 'Sigiriya Rock Fortress',
      region: 'Central Province',
      src: 'https://images.unsplash.com/photo-1586974373029-622f76ab25fa?auto=format&fit=crop&w=1600&q=85',
      fb: 'https://picsum.photos/seed/sigiriya/1600/900',
    },
  ],

  /* в”Ђв”Ђ Section backgrounds в”Ђв”Ђ */
  statsBg: {
    // Parliament interior / session
    src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/1280px-Sri_Lanka_Parliament_2.jpg',
    fb: 'https://picsum.photos/seed/parli2/1600/700',
  },
  featuresBg: {
    // Galle Dutch Fort walls
    src: 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?auto=format&fit=crop&w=1600&q=60',
    fb: 'https://picsum.photos/seed/gallfort/1600/700',
  },
  politiciansBg: {
    // Independence square monument
    src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/1280px-Independence_Memorial_Hall_Sri_Lanka.jpg',
    fb: 'https://picsum.photos/seed/independence/1600/700',
  },
  newsBg: {
    // Kandy Esplanade / city
    src: 'https://images.unsplash.com/photo-1510001618818-4b4e3d86bf0f?auto=format&fit=crop&w=1600&q=60',
    fb: 'https://picsum.photos/seed/kandy/1600/700',
  },
  testimonialsBg: {
    // Sigiriya
    src: 'https://images.unsplash.com/photo-1586974373029-622f76ab25fa?auto=format&fit=crop&w=1600&q=60',
    fb: 'https://picsum.photos/seed/sig2/1600/700',
  },
  ctaBg: {
    // Colombo night skyline / Galle Face
    src: 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=1600&q=85',
    fb: 'https://picsum.photos/seed/colombo2/1600/700',
  },

  /* в”Ђв”Ђ Scrolling strip в”Ђв”Ђ */
  strip: [
    { name: 'Parliament', src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg', fb: 'https://picsum.photos/seed/s1/400/250' },
    { name: "President's House", src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/640px-Presidential_Secretariat%2C_Colombo.jpg', fb: 'https://picsum.photos/seed/s2/400/250' },
    { name: 'Supreme Court', src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Supreme_Court_of_Sri_Lanka.jpg/640px-Supreme_Court_of_Sri_Lanka.jpg', fb: 'https://picsum.photos/seed/s3/400/250' },
    { name: 'Independence Hall', src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/640px-Independence_Memorial_Hall_Sri_Lanka.jpg', fb: 'https://picsum.photos/seed/s4/400/250' },
    { name: 'Galle Face Green', src: 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=400&q=70', fb: 'https://picsum.photos/seed/s5/400/250' },
    { name: 'Sigiriya', src: 'https://images.unsplash.com/photo-1586974373029-622f76ab25fa?auto=format&fit=crop&w=400&q=70', fb: 'https://picsum.photos/seed/s6/400/250' },
    { name: 'Kandy Temple', src: 'https://images.unsplash.com/photo-1510001618818-4b4e3d86bf0f?auto=format&fit=crop&w=400&q=70', fb: 'https://picsum.photos/seed/s7/400/250' },
    { name: 'Galle Fort', src: 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?auto=format&fit=crop&w=400&q=70', fb: 'https://picsum.photos/seed/s8/400/250' },
  ],
};

/* в”Ђв”Ђв”Ђ Politicians вЂ” actual Wikipedia photos в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
const POLITICIANS = [
  {
    name: 'Ranil Wickremesinghe',
    role: 'President of Sri Lanka',
    party: 'UNP',
    promisesKept: 85,
    totalPromises: 120,
    rating: 70.8,
    trend: '+5.2%',
    color: '#FF6B35',
    // Actual photo from Wikipedia
    photo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Ranil_Wickremesinghe_2017.jpg/400px-Ranil_Wickremesinghe_2017.jpg',
    photoFb: 'https://picsum.photos/seed/pol1/400/500',
    // Associated landmark: Presidential Secretariat
    place: "President's Secretariat, Colombo",
    placeImg: 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/640px-Presidential_Secretariat%2C_Colombo.jpg',
    placeImgFb: 'https://picsum.photos/seed/pres1/640/400',
  },
  {
    name: 'Sajith Premadasa',
    role: 'Opposition Leader',
    party: 'SJB',
    promisesKept: 67,
    totalPromises: 95,
    rating: 70.5,
    trend: '+3.8%',
    color: '#1B4D3E',
    photo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Sajith_Premadasa_%28cropped%29.jpg/400px-Sajith_Premadasa_%28cropped%29.jpg',
    photoFb: 'https://picsum.photos/seed/pol2/400/500',
    // Independence Square вЂ” linked to his father's legacy
    place: 'Independence Square, Colombo',
    placeImg: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/640px-Independence_Memorial_Hall_Sri_Lanka.jpg',
    placeImgFb: 'https://picsum.photos/seed/indep2/640/400',
  },
  {
    name: 'Anura Kumara Dissanayake',
    role: 'Party Leader вЂ” NPP',
    party: 'NPP',
    promisesKept: 52,
    totalPromises: 78,
    rating: 66.7,
    trend: '+12.3%',
    color: '#800000',
    photo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2c/Anura_Kumara_Dissanayake.jpg/400px-Anura_Kumara_Dissanayake.jpg',
    photoFb: 'https://picsum.photos/seed/pol3/400/500',
    // Parliament вЂ” he is an active MP
    place: 'Sri Lanka Parliament, Kotte',
    placeImg: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg',
    placeImgFb: 'https://picsum.photos/seed/parl3/640/400',
  },
];

/* в”Ђв”Ђв”Ђ News вЂ” Wikimedia/Unsplash contextual photos в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
const NEWS = [
  {
    title: 'Economic recovery discussions continue in Colombo',
    source: 'Political Desk', time: '2 hours ago', category: 'Economy',
    img: 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=500&q=75',
    imgFb: 'https://picsum.photos/seed/econ/500/300',
  },
  {
    title: 'Parliamentary session debates key governance reform bill',
    source: 'Civic Monitor', time: '5 hours ago', category: 'Governance',
    img: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg',
    imgFb: 'https://picsum.photos/seed/gov/500/300',
  },
  {
    title: 'Youth participation and democratic engagement grow across Sri Lanka',
    source: 'Citizen Watch', time: '1 day ago', category: 'Society',
    img: 'https://images.unsplash.com/photo-1560963689-b5682b6440f8?auto=format&fit=crop&w=500&q=75',
    imgFb: 'https://picsum.photos/seed/soc/500/300',
  },
];

const TESTIMONIALS = [
  { name: 'Nimal Perera',           role: 'Colombo Resident',    img: 'https://randomuser.me/api/portraits/men/11.jpg',   comment: 'This platform clearly shows which promises are being kept and which are not.',    rating: 5 },
  { name: 'Kamala Silva',           role: 'Community Volunteer', img: 'https://randomuser.me/api/portraits/women/21.jpg', comment: 'The visual design and transparent data make this very useful for citizens.',       rating: 5 },
  { name: 'Dr. Asanka Weerasinghe', role: 'University Lecturer', img: 'https://randomuser.me/api/portraits/men/32.jpg',   comment: 'A strong concept for democratic transparency and public participation.',           rating: 5 },
];

const STATS = [
  { id:1, value:225,  label:'Politicians Tracked', icon:UserGroupIcon,           suffix:'+' },
  { id:2, value:1247, label:'Promises Made',        icon:DocumentTextIcon,        suffix:'+' },
  { id:3, value:856,  label:'Promises Kept',        icon:CheckBadgeIcon,          suffix:'+' },
  { id:4, value:3452, label:'Citizen Reports',      icon:ChatBubbleLeftRightIcon, suffix:'+' },
];

const FEATURES = [
  { icon:ShieldCheckIcon,         title:'Promise Tracking',      desc:'Track political promises with status updates, supporting evidence, and public accountability.', gradient:'from-blue-500 to-cyan-500',     stat:'95% Accuracy', delay:0    },
  { icon:ChartBarIcon,            title:'Performance Analytics', desc:'View completion rates, politician ratings, and promise fulfillment history.',                    gradient:'from-purple-500 to-pink-500',  stat:'Live Updates',  delay:0.1  },
  { icon:GlobeAltIcon,            title:'News Integration',      desc:'Connect political news and developments with ongoing promises and public feedback.',              gradient:'from-orange-500 to-red-500',   stat:'24/7 Updates',  delay:0.2  },
  { icon:ChatBubbleLeftRightIcon, title:'Citizen Feedback',      desc:'Let citizens contribute reports, opinions, and evidence for better transparency.',               gradient:'from-green-500 to-emerald-500',stat:'10k+ Reviews',  delay:0.3  },
];

/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
   SHARED UTILITIES
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */

/** Image with automatic fallback on load error */
const Img = ({ src, fb, alt = '', className = '', style = {} }) => {
  const [err, setErr] = useState(false);
  return (
    <img
      src={err ? fb : src}
      alt={alt}
      referrerPolicy="no-referrer"
      crossOrigin="anonymous"
      onError={() => setErr(true)}
      className={className}
      style={style}
    />
  );
};

/** Full-bleed section background with overlay */
const SectionBg = ({ src, fb, opacity = 0.07, overlayClass = 'bg-white/93 dark:bg-gray-900/93' }) => (
  <div className="absolute inset-0 overflow-hidden pointer-events-none">
    <Img src={src} fb={fb} alt="" className="w-full h-full object-cover" style={{ opacity }} />
    <div className={`absolute inset-0 ${overlayClass}`} />
  </div>
);

/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
   HERO вЂ” animated civic landmark slideshow
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */
const HeroSlideshow = () => {
  const [cur, setCur] = useState(0);

  useEffect(() => {
    const t = setInterval(() => setCur(c => (c + 1) % IMGS.hero.length), 5500);
    return () => clearInterval(t);
  }, []);

  return (
    <div className="absolute inset-0 z-0">
      {IMGS.hero.map((slide, i) => (
        <AnimatePresence key={i}>
          {i === cur && (
            <motion.div
              key={`hero-${i}`}
              className="absolute inset-0"
              initial={{ opacity: 0, scale: 1.06 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.6, ease: 'easeInOut' }}
            >
              <Img
                src={slide.src}
                fb={slide.fb}
                alt={slide.name}
                className="w-full h-full object-cover"
              />
            </motion.div>
          )}
        </AnimatePresence>
      ))}

      {/* Dark gradient overlay вЂ” strong top, fades to warm at bottom */}
      <div className="absolute inset-0 bg-gradient-to-b from-black/70 via-black/50 to-orange-950/85 z-10" />
      <div className="absolute inset-0 bg-gradient-to-r from-black/25 via-transparent to-black/15 z-10" />

      {/* Current location label */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center gap-3">
        <AnimatePresence mode="wait">
          <motion.div
            key={`label-${cur}`}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -6 }}
            transition={{ duration: 0.55 }}
            className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-black/30 backdrop-blur-md border border-white/20"
          >
            <MapPinIcon className="w-4 h-4 text-orange-300 flex-shrink-0" />
            <span className="text-white/95 text-sm font-semibold">{IMGS.hero[cur].name}</span>
            <span className="text-white/45 text-xs hidden sm:inline">В· {IMGS.hero[cur].region}</span>
          </motion.div>
        </AnimatePresence>

        {/* Slide dot indicators */}
        <div className="flex items-center gap-2">
          {IMGS.hero.map((_, i) => (
            <button
              key={i}
              onClick={() => setCur(i)}
              aria-label={`Slide ${i + 1}`}
              style={{
                width: i === cur ? 26 : 8, height: 8, padding: 0,
                borderRadius: 4, border: 'none', cursor: 'pointer',
                background: i === cur ? '#F59E0B' : 'rgba(255,255,255,0.32)',
                transition: 'all 0.35s ease',
              }}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
   SCROLLING LANDMARK STRIP
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */
const LandmarkStrip = () => {
  const doubled = [...IMGS.strip, ...IMGS.strip];
  return (
