                <div className="flex items-center mb-4">
                  <img
                    src={t.img} alt={t.name} referrerPolicy="no-referrer"
                    className="w-12 h-12 rounded-full object-cover mr-4"
                    onError={e => { e.target.src = `https://picsum.photos/seed/tm${i}/80/80`; }}
                  />
                  <div>
                    <h4 className="font-bold text-gray-900 dark:text-white">{t.name}</h4>
                    <p className="text-sm text-gray-500 dark:text-gray-400">{t.role}</p>
                  </div>
                </div>
                <div className="flex mb-3">
                  {[...Array(t.rating)].map((_, j) => (
                    <StarIcon key={j} className="w-5 h-5 text-yellow-400 fill-current" />
                  ))}
                </div>
                <p className="text-gray-600 dark:text-gray-400 italic">"{t.comment}"</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* в•ђв•ђ CTA вЂ” Colombo skyline full bleed в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */}
      <section className="py-24 relative overflow-hidden">
        <div className="absolute inset-0">
          <Img
            src={IMGS.ctaBg.src} fb={IMGS.ctaBg.fb} alt=""
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-r from-orange-600/93 to-red-800/93" />
        </div>
        <div className="relative z-10 container mx-auto px-4 text-center">
          <motion.div initial={{ opacity:0, y:20 }} whileInView={{ opacity:1, y:0 }} className="max-w-3xl mx-auto">
            <h2 className="text-4xl md:text-5xl font-bold text-white mb-6 drop-shadow">Ready to Make a Difference?</h2>
            <p className="text-xl text-white/90 mb-8">Join the movement for transparent governance in Sri Lanka.</p>
            <Link
              to="/register"
              className="inline-flex items-center px-8 py-4 bg-white text-orange-600 rounded-xl font-bold text-lg hover:shadow-2xl transform hover:scale-105 transition-all"
            >
              Get Started Now <ArrowRightIcon className="w-5 h-5 ml-2" />
            </Link>
          </motion.div>
        </div>
      </section>

      {/* в•ђв•ђ FLOATING BUTTON в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */}
      <motion.button
        initial={{ scale:0 }} animate={{ scale:1 }} whileHover={{ scale:1.1 }}
        className="fixed bottom-8 right-8 z-50 bg-gradient-to-r from-orange-500 to-red-700 text-white p-4 rounded-full shadow-2xl"
      >
        <ChatBubbleLeftRightIcon className="w-6 h-6" />
      </motion.button>

    </div>
  );
};

export default Home;
